/* OfferMapper.insertOffer : 제안 생성 */
INSERT INTO tb_offer (
     offer_id
    ,offer_uid
    ,offer_status_code
    ,offer_at
    ,offer_amount
    ,offer_position_addr
    ,offer_position_distance
    ,offer_position_latt
    ,offer_position_lngt
    ,offer_memo_content
    ,create_at
    ,create_id
) VALUES (
     nextval('seq_tb_offer_offer_id')::text
    ,#{offerUid}
    ,#{offerStatusType}
    ,#{offerAt}
    ,#{price}
    ,#{offerLocationAddress}
    ,#{offerLocationDistance}
    ,#{offerLocationLatitude}
    ,#{offerLocationLongitude}
    ,#{offerMemo}
    ,NOW()
    ,#{offerUid}
)

