/* OfferMapper.updateOffer : 제안 수정 */
UPDATE tb_offer

    update_at = NOW()

        , update_id = #{updateId}


        , offer_status_code = #{offerStatusType}


        , offer_at = #{offerAt}


        , offer_amount = #{price}


        , offer_position_addr = #{offerLocationAddress}


        , offer_position_distance = #{offerLocationDistance}


        , offer_position_latt = #{offerLocationLatitude}


        , offer_position_lngt = #{offerLocationLongitude}


        , offer_memo_content = #{offerMemo}


WHERE offer_id = #{offerId}
  AND delete_yn = 'N'

