    ,offer_id
    ,treatment_level
    ,treatment_code
    ,create_at
    ,create_id
) VALUES (
     nextval('seq_tb_offer_treatment_offer_treatment_id')::text
    ,#{offerId}
    ,#{treatmentLevel}
    ,#{treatmentCode}
    ,NOW()
    ,'system'
)

