/* OfferMapper.deleteOfferTreatmentsByOfferId : 제안 시술 전체 삭제 */
UPDATE tb_offer_treatment
SET delete_yn = 'Y', delete_at = NOW()
WHERE offer_id = #{offerId}
  AND delete_yn = 'N'

